/**
 * Initialize Envelope (TVPX__30)
 * - Normalizes inbound payloads
 * - Ensures ctx exists
 * - Ensures concept_id is optional (we can pick one)
 */

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();
const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};

const traceSeed = JSON.stringify(incoming).slice(0, 5000) + '::' + now;
const traceId = baseCtx.trace_id || `tvpx_${fnv1a(traceSeed)}`;
const familyId = baseCtx.asset_family_id || `tvpxfam_${fnv1a(traceId + '::family')}`;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: traceId,
  asset_family_id: familyId,
  trigger_mode: baseCtx.trigger_mode || incoming.trigger_mode || 'internal',
  route_mode: 'image_generate_dual',
  received_at: now,
  telegram_chat_id: String(baseCtx.telegram_chat_id || incoming.telegram_chat_id || incoming?.tg?.chat_id || incoming?.tg?.chat?.id || incoming.chat_id || '').trim() || null,
  fal_api_key: String(baseCtx.fal_api_key || incoming.fal_api_key || '').trim(),
  fal_endpoint_url: String(baseCtx.fal_endpoint_url || incoming.fal_endpoint_url || '').trim(),

  // optional knobs
  image_size: String(baseCtx.image_size || incoming.image_size || '1024x1280'),
  output_format: String(baseCtx.output_format || incoming.output_format || 'png'),
  background: String(baseCtx.background || incoming.background || 'opaque'),
  quality: String(baseCtx.quality || incoming.quality || 'high'),
  poll_max: Number(baseCtx.poll_max || incoming.poll_max || 24),
  lock_ttl_minutes: Number(baseCtx.lock_ttl_minutes || incoming.lock_ttl_minutes || 15)
};

const conceptId = String(incoming.concept_id || baseCtx.concept_id || '').trim();

return [{
  json: {
    ctx,
    input: incoming.input || incoming,
    carry: incoming.carry || {},
    concept_id: conceptId || null
  }
}];

/**
 * Select Best Concept
 * - Anti-stock bias: prefer higher quality_score, lower used_count
 * - Safe if table returns different field shapes
 */

const base = $items('Initialize Envelope')[0].json;
const ctx = base.ctx;

const rows = $input.all().map(i => i.json);
if (!rows.length) {
  throw new Error('No ready concepts found in tvpx_concept_pool.');
}

function n(v, d=0){
  const x = Number(v);
  return Number.isFinite(x) ? x : d;
}

// Weighted score: quality dominates; penalize repetition
const scored = rows.map(r => {
  const quality = n(r.quality_score, 0);
  const used = n(r.used_count, 0);
  const abstraction = n(r.abstraction_target, 6.2);
  const noveltyPenalty = Math.min(used * 0.35, 2.0);
  const abstractionPenalty = (abstraction < 5.4 || abstraction > 7.6) ? 0.6 : 0;
  const score = quality - noveltyPenalty - abstractionPenalty;
  return { r, score };
}).sort((a,b) => b.score - a.score);

const picked = scored[0].r;
const conceptId = String(picked.concept_id || picked.id || picked.dt_row_id || '').trim();
if (!conceptId) throw new Error('Concept row missing concept_id.');

return [{
  json: {
    ctx,
    concept_id: conceptId,
    concept_row: picked
  }
}];

/**
 * Reattach Context After Get Concept
 * Converts DataTable row to canonical envelope.
 */

const base = $items('Initialize Envelope')[0].json;
const ctx = base.ctx;

const row = $input.all()[0]?.json || null;
if (!row) throw new Error('Concept not found for provided concept_id.');

const conceptId = String(row.concept_id || row.id || row.dt_row_id || '').trim();
if (!conceptId) throw new Error('Fetched concept row missing concept_id.');

return [{
  json: {
    ctx,
    concept_id: conceptId,
    concept_row: row
  }
}];

/**
 * Build Lock Payload
 */

const j = $json;
const ctx = j.ctx;
const now = new Date();
const expires = new Date(now.getTime() + (Number(ctx.lock_ttl_minutes || 15) * 60_000));

return [{
  json: {
    ...j,
    lock: {
      lock_owner: ctx.trace_id,
      lock_expires_at: expires.toISOString(),
      locked_at: now.toISOString()
    }
  }
}];

/**
 * Verify Lock Ownership
 * Ensures we own the lock; otherwise bail safely.
 */

const base = $items('Build Lock Payload')[0].json;
const ctx = base.ctx;
const row = $input.all()[0]?.json;
if (!row) throw new Error('Failed to refetch locked concept row.');

const owner = String(row.lock_owner || '').trim();
const state = String(row.state || '').trim();

if (state !== 'locked' || owner !== ctx.trace_id) {
  throw new Error(`Lock not acquired. state='${state}' lock_owner='${owner}' expected='${ctx.trace_id}'`);
}

return [{
  json: {
    ctx,
    concept_id: base.concept_id,
    concept_row: row
  }
}];

