function parseStrictJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('Parser: empty LLM output.');

  const candidates = [
    text,
    text.replace(/```json\s*/gi, '').replace(/```/g, '').trim()
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    try {
      return JSON.parse(slice);
    } catch (err) {
      throw new Error(`Parser: invalid salvaged JSON. ${err.message}`);
    }
  }

  throw new Error('Parser: could not find a valid JSON object.');
}

const BASE_NODE = 'Verify Lock Ownership';
const OUT_KEY = 'render_spec';

const base = $items(BASE_NODE)[0]?.json;
if (!base) {
  throw new Error(`Parser: base node "${BASE_NODE}" returned no data.`);
}

const parsed = parseStrictJson($json);

// Per-output hardening
if (OUT_KEY === 'critic') {
  parsed.approve = Boolean(parsed.approve);
  for (const key of ['score', 'brand_fit', 'novelty', 'visual_viability']) {
    parsed[key] = Number(parsed[key] || 0);
  }
}

if (OUT_KEY === 'abstraction') {
  let a = Number(parsed.abstraction_target || 6.2);
  const min = Number(base.ctx?.target_abstraction_min || 5.8);
  const max = Number(base.ctx?.target_abstraction_max || 6.8);
  if (!Number.isFinite(a)) a = 6.2;
  a = Math.max(min, Math.min(max, a));
  parsed.abstraction_target = Math.round(a * 10) / 10;
}

if (OUT_KEY === 'render_spec') {
  parsed.image_size = String(parsed.image_size || base.ctx?.image_size || '1024x1280');
  parsed.provider_controls = (parsed.provider_controls && typeof parsed.provider_controls === 'object')
    ? parsed.provider_controls
    : {};
  parsed.provider_controls.quality = String(parsed.provider_controls.quality || base.ctx?.quality || 'high');
  parsed.provider_controls.background = String(parsed.provider_controls.background || base.ctx?.background || 'opaque');
  parsed.provider_controls.output_format = String(parsed.provider_controls.output_format || base.ctx?.output_format || 'png');
}

if (OUT_KEY === 'caption_pack') {
  parsed.hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];
  parsed.keywords = Array.isArray(parsed.keywords) ? parsed.keywords : [];
}

if (OUT_KEY === 'series_plan') {
  parsed.variations = Array.isArray(parsed.variations) ? parsed.variations : [];
}

return [{
  json: {
    ...base,
    [OUT_KEY]: parsed
  }
}];

/**
 * Build Dual Render Packets
 * Produces two items: color and bw, derived from same master.
 */

const j = $json;
const ctx = j.ctx;
const spec = j.render_spec;

const master = String(spec.master_prompt || '').trim();
const negative = String(spec.negative_prompt || '').trim();
if (master.length < 40) throw new Error('Bad render spec: master_prompt too short.');

const imageSize = String(spec.image_size || '1024x1280');
const controls = spec.provider_controls || {};

const colorPrompt = [
  master,
  'Color grade: muted cinematic base (olive/sepia/ashen cream/damp gray) with at most one meaningful saturation puncture (amber/marigold/turquoise/orange).',
  'Lighting: chiaroscuro or diffused haze; preserve tactile materials and surface tension.'
].join(' ');

const bwPrompt = [
  master,
  'Black-and-white only. No color cast. Silver-gelatin tonal separation, velvet blacks, luminous midtones, tactile surface contrast, atmospheric haze.'
].join(' ');

const common = {
  image_size: imageSize,
  background: String(controls.background || 'opaque'),
  quality: String(controls.quality || 'high'),
  output_format: String(controls.output_format || 'png')
};

return [
  {
    json: {
      ctx,
      concept_id: j.concept_id,
      concept_row: j.concept_row,
      render_variant: 'color',
      prompt: colorPrompt,
      negative_prompt: negative,
      provider_controls: common
    }
  },
  {
    json: {
      ctx,
      concept_id: j.concept_id,
      concept_row: j.concept_row,
      render_variant: 'bw',
      prompt: bwPrompt,
      negative_prompt: negative,
      provider_controls: common
    }
  }
];

/**
 * Assemble Asset Family
 * Expects two subworkflow results; normalizes into a single payload for Workflow 40.
 */

const items = $input.all().map(i => i.json);

// We expect each item includes render_variant and image_url
const by = {};
for (const it of items) {
  const k = String(it.render_variant || '').trim();
  if (k) by[k] = it;
}

const color = by.color;
const bw = by.bw;
if (!color || !bw) {
  throw new Error(`Missing color or bw render results. Got keys: ${Object.keys(by).join(', ')}`);
}

const ctx = color.ctx || bw.ctx;

return [{
  json: {
    ctx,
    concept_id: String(color.concept_id || bw.concept_id || '').trim(),
    asset_family_id: ctx.asset_family_id,
    family: {
      color,
      bw
    }
  }
}];

/**
 * Failure Audit Builder
 * Use this on any branch you decide to wire into it.
 */

const base = $items('Initialize Envelope')[0].json;
const ctx = base.ctx;
const now = new Date().toISOString();

return [{
  json: {
    ctx,
    failure: {
      failure_id: `tvpx_fail_${ctx.trace_id}_${now.replace(/[:.]/g,'')}`,
      trace_id: ctx.trace_id,
      stage_name: 'TVPX__30__Image Generation Dual Mode',
      entity_type: 'concept',
      entity_id: String(base.concept_id || ''),
      severity: 'error',
      payload_snapshot_json: JSON.stringify(base).slice(0, 18000),
      error_text: 'See execution logs (n8n).',
      retry_count: 0,
      status: 'open',
      created_at: now
    }
  }
}];
